import{_ as r,o as t,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Historical Quick Link Access for Self-Serve Customers","description":"","frontmatter":{"title":"Historical Quick Link Access for Self-Serve Customers","slug":"historical-quick-link-access-for-self-serve-customers"},"headers":[],"relativePath":"account-hub/historical-quick-link-access-for-self-serve-customers.md","filePath":"account-hub/historical-quick-link-access-for-self-serve-customers.md"}'),i={name:"account-hub/historical-quick-link-access-for-self-serve-customers.md"};function s(n,e,c,l,d,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<p>Self-serve customers will need to enter a valid credit card into their billing profile by <strong>February 17, 2025</strong> in order to recover Branch Short Links they created prior to June 21, 2023.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To regain access to your Branch Short Links created prior to June 21, 2023, you will need to add a valid credit card prior to the February 17, 2025 deadline.</p><p>Self-serve accounts that do not have a valid credit card added to their billing profile by February 17, 2025 will see all Branch Short Links created prior to June 21, 2023 removed permanently. Branch will not be able to restore these links after the deadline.</p><p><strong>Please note that clicking on a Branch Short Link after it has been deleted by Branch means the user will get redirected based on your app-level fallback configuration.</strong></p><h2 id="exclusions" tabindex="-1">Exclusions <a class="header-anchor" href="#exclusions" aria-label="Permalink to &quot;Exclusions&quot;">​</a></h2><p>Excluded from this change are existing API-generated Branch Links as well as Branch Ad Links.</p><h2 id="how-to-maintain-access" tabindex="-1">How to Maintain Access <a class="header-anchor" href="#how-to-maintain-access" aria-label="Permalink to &quot;How to Maintain Access&quot;">​</a></h2><p>To maintain access to your Branch Short Links created prior to June 21, 2023, <strong>please complete the following steps prior to February 17, 2025</strong>:</p><ol><li>Log in to your Branch account through the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Under the <strong>Configure</strong> section, click on <strong>Account Settings</strong>. Then click on the <strong>Billing</strong> tab.</li><li>Select <strong>Add Payment Method</strong>.</li><li>Enter a valid credit card.</li></ol><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><p>Visit the Products <a href="./products.html">page</a> for an overview of Branch&#39;s powerful suite of products.</p><p>If you&#39;re ready to discuss Branch packaging in more detail, <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our sales team</a> to get started!</p>',13)])])}const f=r(i,[["render",s]]);export{p as __pageData,f as default};
